import{_ as o,o as r,c as e,ag as a}from"./chunks/framework.BLeoozAw.js";const u=JSON.parse('{"title":"SRC 攻防实操手册","description":"从 0 到 1 的漏洞挖掘攻防全向图谱，汇聚实战中的血与泪。","frontmatter":{"title":"SRC 攻防实操手册","description":"从 0 到 1 的漏洞挖掘攻防全向图谱，汇聚实战中的血与泪。"},"headers":[],"relativePath":"experience/README.md","filePath":"experience/README.md"}'),i={name:"experience/README.md"};function l(s,t,n,c,p,g){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="🛡️-src-攻防实战经验库-target-centric-playbooks" tabindex="-1">🛡️ SRC 攻防实战经验库 (Target-Centric Playbooks) <a class="header-anchor" href="#🛡️-src-攻防实战经验库-target-centric-playbooks" aria-label="Permalink to &quot;🛡️ SRC 攻防实战经验库 (Target-Centric Playbooks)&quot;">​</a></h1><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>探索路线</strong>: 本部分按照<strong>目标类型 (Target Type)</strong> 进行分类映射：物联网 (IoT)、Web 应用、云原生 (Cloud) 以及基础设施 (Infrastructure)。每篇 Playbook 均遵循“背景 -&gt; 攻坚 -&gt; 自动化”的职业级闭环。</p></div><h2 id="💡-核心攻坚领域" tabindex="-1">💡 核心攻坚领域 <a class="header-anchor" href="#💡-核心攻坚领域" aria-label="Permalink to &quot;💡 核心攻坚领域&quot;">​</a></h2><p>这里的每一篇文章都是从上千个 403、500 报错中提炼出的实战精华：</p><ul><li><strong>📡 IoT &amp; 终端</strong>: 攻破硬件边界，深入固件与专有协议。</li><li><strong>🌐 Web &amp; 业务</strong>: 403 绕过、逻辑缺陷与现代 WAF 下的 Payload 进化。</li><li><strong>☁️ Cloud &amp; 云原生</strong>: 元数据、S3 桶与云厂商特有的攻击向量。</li><li><strong>🏰 Infra &amp; 架构</strong>: Web 服务器缺陷、DNS 劫持与内网横向基础。</li></ul><hr><h2 id="🏆-白帽进阶指南-如何成为-p1-p0-捕手" tabindex="-1">🏆 白帽进阶指南：如何成为 P1/P0 捕手 <a class="header-anchor" href="#🏆-白帽进阶指南-如何成为-p1-p0-捕手" aria-label="Permalink to &quot;🏆 白帽进阶指南：如何成为 P1/P0 捕手&quot;">​</a></h2><ol><li><strong>资产深挖</strong>: 国内优先攻击<strong>核心资产</strong>（边缘资产收益极低）。优先测试中高危，通过低危漏洞建立信心。</li><li><strong>逆向思维</strong>: 始终以<strong>开发者的视角</strong>思考：如果是我想实现这个功能，我会如何写代码？我会漏掉什么样的校验逻辑？</li><li><strong>思路闭环</strong>: <ul><li>🔍 发现点位 (Discovery)</li><li>🧪 复现验证 (Reproduction)</li><li>📜 沉淀思路 (Summarization)</li><li>🤖 自动化 (Automation)</li></ul></li><li><strong>执着与身体</strong>: 兴趣是第一动力，但在卷的同时，请务必保证休息。</li></ol><hr><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>贡献者须知</strong>: 如果你也有好的实战故事，只需在 <code>experience/</code> 下创建一个目录并提交 Markdown，我们的<strong>自动化引擎</strong>会自动为你完成同步。</p></div><hr>',11)])])}const m=o(i,[["render",l]]);export{u as __pageData,m as default};
